mapper.update:
update clazz
name = #{name}, room = #{room}, begin_date = #{beginDate}, end_date = #{endDate}, master_id = #{masterId}, subject = #{subject},
where id = #{id}

mapper.select:
select c.*, e.name as masterName
from clazz c
left join emp e on c.master_id = e.id

    and c.name like concat('%', #{name}, '%')
    and c.room like concat('%', #{room}, '%')
    and c.begin_date >= #{beginDate}
    and c.end_date <= #{endDate}
    and c.master_id = #{masterId}
    and c.subject = #{subject}

order by c.create_time desc
limit #{offset}, #{pageSize}

select count(*)
from clazz c

    and c.name like concat('%', #{name}, '%')
    and c.room like concat('%', #{room}, '%')
    and c.begin_date >= #{beginDate}
    and c.end_date <= #{endDate}
    and c.master_id = #{masterId}
    and c.subject = #{subject}
